from flask import Flask, request, jsonify
from web3 import Web3
import json
import hashlib
from datetime import datetime, timedelta
import secrets

app = Flask(__name__)

# Configuration
WEB3_PROVIDER = "https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID"
MAX_TOKEN_AGE = 3600  # 1 hour

# Initialize web3
w3 = Web3(Web3.HTTPProvider(WEB3_PROVIDER))

# In production, use a proper database or cache
active_tokens = {}

def validate_ethereum_address(address):
    """Validate Ethereum address format"""
    if not address or not address.startswith('0x') or len(address) != 42:
        return False
    return w3.isAddress(address)

def verify_signature(message, signature, address):
    """Verify Ethereum signature"""
    try:
        # Recover address from signature
        recovered_address = w3.eth.account.recover_message(message, signature=signature)
        
        # Compare recovered address with provided address
        return recovered_address.lower() == address.lower()
    except Exception:
        return False

def generate_token():
    """Generate secure authentication token"""
    return secrets.token_urlsafe(32)

def is_token_valid(token):
    """Check if token is still valid"""
    if token not in active_tokens:
        return False
    
    # Check if token has expired
    if datetime.now() > active_tokens[token]['expires']:
        del active_tokens[token]
        return False
    
    return True

@app.route('/auth/login', methods=['POST'])
def authenticate():
    """Authenticate user with Ethereum signature"""
    try:
        data = request.get_json()
        
        # Validate request data
        if not data or 'address' not in data or 'signature' not in data or 'message' not in data:
            return jsonify({'error': 'Missing required fields'}), 400
        
        address = data['address']
        signature = data['signature']
        message = data['message']
        
        # Validate address format
        if not validate_ethereum_address(address):
            return jsonify({'error': 'Invalid Ethereum address'}), 400
        
        # Verify signature
        if not verify_signature(message, signature, address):
            return jsonify({'error': 'Invalid signature'}), 401
        
        # Generate authentication token
        token = generate_token()
        expires = datetime.now() + timedelta(seconds=MAX_TOKEN_AGE)
        
        # Store token
        active_tokens[token] = {
            'address': address,
            'expires': expires
        }
        
        return jsonify({
            'token': token,
            'address': address,
            'expires': expires.isoformat()
        }), 200
        
    except Exception as e:
        return jsonify({'error': 'Authentication failed'}), 500

@app.route('/auth/verify', methods=['POST'])
def verify_token():
    """Verify authentication token"""
    try:
        data = request.get_json()
        
        if not data or 'token' not in data:
            return jsonify({'error': 'Missing token'}), 400
        
        token = data['token']
        
        if not is_token_valid(token):
            return jsonify({'error': 'Invalid or expired token'}), 401
        
        return jsonify({
            'valid': True,
            'address': active_tokens[token]['address']
        }), 200
        
    except Exception as e:
        return jsonify({'error': 'Verification failed'}), 500

@app.route('/auth/logout', methods=['POST'])
def logout():
    """Logout user by invalidating token"""
    try:
        data = request.get_json()
        
        if not data or 'token' not in data:
            return jsonify({'error': 'Missing token'}), 400
        
        token = data['token']
        
        if token in active_tokens:
            del active_tokens[token]
        
        return jsonify({'message': 'Logged out successfully'}), 200
        
    except Exception as e:
        return jsonify({'error': 'Logout failed'}), 500

if __name__ == '__main__':
    app.run(debug=False, host='0.0.0.0', port=5000)